sql:
SELECT job_title
FROM job_postings
ORDER BY job_title ASC;

SELECT MAX(application_date)
FROM job_applications
WHERE user_id = 1;

SELECT status
FROM job_applications
WHERE application_id = 1;

SELECT DISTINCT job_type
FROM job_postings
ORDER BY job_type;

SELECT COUNT(user_id) AS user_count
FROM training_registrations
WHERE training_id = 1;
